sessionStart.powershell:
$inputText = [Console]::In.ReadToEnd()
$logLevel = if ($env:VSTACK_HOOKS_LOG_LEVEL) { $env:VSTACK_HOOKS_LOG_LEVEL } else { 'minimal' }
$logRoot = if ($env:VSTACK_HOOK_LOG_DIR) { $env:VSTACK_HOOK_LOG_DIR } else { '.vstack/logs' }
$retentionDaysRaw = if ($env:VSTACK_HOOK_RETENTION_DAYS) { $env:VSTACK_HOOK_RETENTION_DAYS } else { '7' }
$retentionDays = 7
if (-not ([int]::TryParse([string]$retentionDaysRaw, [ref]$retentionDays) -and $retentionDays -gt 0)) {
  $retentionDays = 7
}
try {
  if (Test-Path -LiteralPath $logRoot) {
    $cutoffDay = (Get-Date).ToUniversalTime().AddDays(-$retentionDays).ToString('yyyyMMdd')
    Get-ChildItem -LiteralPath $logRoot -Directory -ErrorAction Stop |
      Where-Object { $_.Name -match '^\d{8}$' -and $_.Name -lt $cutoffDay } |
      ForEach-Object { Remove-Item -LiteralPath $_.FullName -Recurse -Force -ErrorAction SilentlyContinue }
  }
} catch {}
$logDir = Join-Path $logRoot (Get-Date).ToUniversalTime().ToString('yyyyMMdd')
New-Item -ItemType Directory -Force -Path $logDir | Out-Null
if ($logLevel -eq 'off') { exit 0 }
if ($logLevel -eq 'verbose') {
  Add-Content -Path (Join-Path $logDir 'hook-agent-call.log') -Value $inputText
  exit 0
}

$scriptStart = Get-Date
$unknownEventsPath = Join-Path $logDir 'hook-agent-call-unknown-events.tsv'

function Get-PathValue {
  param([object]$Object, [string]$Path)
  $current = $Object
  foreach ($part in $Path.Split('.')) {
    if ($null -eq $current) { return $null }
    $prop = $current.PSObject.Properties[$part]
    if ($null -eq $prop) { return $null }
    $current = $prop.Value
  }
  return $current
}

function Get-FirstString {
  param([object]$Object, [string[]]$Paths)
  foreach ($path in $Paths) {
    $value = Get-PathValue -Object $Object -Path $path
    if ($null -ne $value -and [string]$value -ne '') { return [string]$value }
  }
  return $null
}

function Add-UnknownEventCounter {
  param(
    [string]$Path,
    [string]$SessionId,
    [string]$Reason
  )

  $counts = @{}
  if (Test-Path $Path) {
    foreach ($line in (Get-Content -Path $Path)) {
      if ([string]::IsNullOrWhiteSpace($line)) { continue }
      $parts = $line -split "`t"
      if ($parts.Count -lt 2) { continue }

      $sid = [string]$parts[0]
      $why = [string]$parts[1]
      $count = 1
      if ($parts.Count -ge 3) {
        $parsedCount = 0
        if ([int]::TryParse([string]$parts[2], [ref]$parsedCount)) {
          $count = [int][Math]::Max(0, $parsedCount)
        }
      }

      $key = "$sid`t$why"
      if (-not $counts.ContainsKey($key)) { $counts[$key] = 0 }
      $counts[$key] += $count
    }
  }

  $target = "$SessionId`t$Reason"
  if (-not $counts.ContainsKey($target)) { $counts[$target] = 0 }
  $counts[$target] += 1

  $rows = foreach ($entry in ($counts.GetEnumerator() | Sort-Object Name)) {
    "{0}`t{1}" -f $entry.Name, $entry.Value
  }
  Set-Content -Path $Path -Value $rows
}

$payload = $null
try { $payload = $inputText | ConvertFrom-Json -ErrorAction Stop } catch {}

$sessionId = 'unknown-session'
$actorName = 'unknown'
$actorType = 'unknown'
$modelUsed = 'unknown'

if ($null -ne $payload) {
  $sessionIdCandidate = Get-FirstString -Object $payload -Paths @('sessionId', 'session_id', 'conversationId', 'conversation_id', 'chatId', 'chat_id')
  if ($sessionIdCandidate) { $sessionId = $sessionIdCandidate }

  $actorNameCandidate = Get-FirstString -Object $payload -Paths @('actorName', 'actor_name', 'subagentName', 'subagent_name', 'agentName', 'agent_name')
  if ($actorNameCandidate) { $actorName = $actorNameCandidate }

  $actorTypeCandidate = Get-FirstString -Object $payload -Paths @('actorType', 'actor_type')
  if ($actorTypeCandidate) { $actorType = $actorTypeCandidate }

  $modelCandidate = Get-FirstString -Object $payload -Paths @('model', 'modelName', 'model_name', 'toolModel', 'tool_model', 'toolCall.model', 'tool_call.model', 'arguments.model', 'arguments.modelName', 'arguments.model_name', 'args.model', 'args.modelName', 'args.model_name', 'tool.arguments.model', 'tool.arguments.modelName', 'tool.arguments.model_name', 'toolCall.arguments.model', 'toolCall.arguments.modelName', 'toolCall.arguments.model_name', 'tool_call.arguments.model', 'tool_call.arguments.modelName', 'tool_call.arguments.model_name')
  if ($modelCandidate) { $modelUsed = $modelCandidate }
}

if ($actorType -eq 'unknown') {
  if ($actorName -match 'subagent') {
    $actorType = 'subagent'
  } elseif ($actorName -ne 'unknown') {
    $actorType = 'agent'
  }
}

if ($actorName -eq 'unknown') {
  Add-UnknownEventCounter -Path $unknownEventsPath -SessionId $sessionId -Reason 'sessionStart_unknown_actor'
  exit 0
}

$sizeBytes = [System.Text.Encoding]::UTF8.GetByteCount($inputText)
$hookExecutionMs = [int][Math]::Max(0, ((Get-Date) - $scriptStart).TotalMilliseconds)
$record = @{
  timestamp = (Get-Date).ToUniversalTime().ToString('o')
  event = 'sessionStart'
  session_id = $sessionId
  actor_name = $actorName
  actor_type = $actorType
  model_used = $modelUsed
  size_bytes = $sizeBytes
  estimated_tokens = [int][math]::Ceiling($sizeBytes / 4.0)
  hook_execution_ms = $hookExecutionMs
} | ConvertTo-Json -Compress
Add-Content -Path (Join-Path $logDir 'hook-agent-call.log') -Value $record

