      $unknownTotal += [int]$entry.Value
      $summaryPairs += ("{0}={1}" -f $entry.Name, $entry.Value)
    }
    $summary = $summaryPairs -join ';'
    $summaryRecord = @{
      timestamp = (Get-Date).ToUniversalTime().ToString('o')
      event = 'unknownSummary'
      session_id = $sessionId
      unknown_total = $unknownTotal
      unknown_breakdown = $summary
      model_used = $modelUsed
