  }

  $remaining = @()
  foreach ($entry in ($remainingCounts.GetEnumerator() | Sort-Object Name)) {
    $remaining += ("{0}`t{1}" -f $entry.Name, $entry.Value)
  }
  Set-Content -Path $unknownEventsPath -Value $remaining
}

