  }
  Set-Content -Path $Path -Value $rows
}

$payload = $null
try { $payload = $inputText | ConvertFrom-Json -ErrorAction Stop } catch {}

$sessionId = 'unknown-session'
$actorName = 'unknown'
$actorType = 'unknown'
$toolName = 'unknown'
$toolCallId = 'unknown'
$delegatedAgentName = 'unknown'
$modelUsed = 'unknown'

if ($null -ne $payload) {
  $sessionIdCandidate = Get-FirstString -Object $payload -Paths @('sessionId', 'session_id', 'conversationId', 'conversation_id', 'chatId', 'chat_id')
  if ($sessionIdCandidate) { $sessionId = $sessionIdCandidate }

  $actorNameCandidate = Get-FirstString -Object $payload -Paths @('actorName', 'actor_name', 'subagentName', 'subagent_name', 'agentName', 'agent_name')
  if ($actorNameCandidate) { $actorName = $actorNameCandidate }

  $actorTypeCandidate = Get-FirstString -Object $payload -Paths @('actorType', 'actor_type')
  if ($actorTypeCandidate) { $actorType = $actorTypeCandidate }

  $toolNameCandidate = Get-FirstString -Object $payload -Paths @('toolName', 'tool_name', 'recipient_name', 'tool.name', 'toolCall.name', 'toolCall.toolName', 'tool_call.name', 'tool_call.tool_name')
  if ($toolNameCandidate) { $toolName = $toolNameCandidate }

  $toolCallIdCandidate = Get-FirstString -Object $payload -Paths @('toolCallId', 'tool_call_id', 'callId', 'call_id', 'toolCall.id', 'tool_call.id')
  if ($toolCallIdCandidate) { $toolCallId = $toolCallIdCandidate }

  $delegatedCandidate = Get-FirstString -Object $payload -Paths @('delegatedAgentName', 'delegated_agent_name', 'runSubagent.agentName', 'runSubagent.agent_name', 'arguments.agentName', 'arguments.agent_name', 'args.agentName', 'args.agent_name', 'tool.arguments.agentName', 'tool.arguments.agent_name', 'toolCall.arguments.agentName', 'toolCall.arguments.agent_name', 'tool_call.arguments.agentName', 'tool_call.arguments.agent_name')
  if ($delegatedCandidate) { $delegatedAgentName = $delegatedCandidate }

  $modelCandidate = Get-FirstString -Object $payload -Paths @('model', 'modelName', 'model_name', 'toolModel', 'tool_model', 'toolCall.model', 'tool_call.model', 'arguments.model', 'arguments.modelName', 'arguments.model_name', 'args.model', 'args.modelName', 'args.model_name', 'tool.arguments.model', 'tool.arguments.modelName', 'tool.arguments.model_name', 'toolCall.arguments.model', 'toolCall.arguments.modelName', 'toolCall.arguments.model_name', 'tool_call.arguments.model', 'tool_call.arguments.modelName', 'tool_call.arguments.model_name')
  if ($modelCandidate) { $modelUsed = $modelCandidate }
}

if ($actorType -eq 'unknown') {
  if ($actorName -match 'subagent') {
    $actorType = 'subagent'
  } elseif ($actorName -ne 'unknown') {
    $actorType = 'agent'
  }
}

if ($toolName -eq 'unknown') {
  $toolNameMatch = [regex]::Match($inputText, '[A-Za-z_][A-Za-z0-9_]*\.[A-Za-z_][A-Za-z0-9_]*')
  if ($toolNameMatch.Success) { $toolName = $toolNameMatch.Value }
}

if ($toolName -eq 'runSubagent' -and $delegatedAgentName -eq 'unknown' -and $null -ne $payload) {
  $delegatedFallback = Get-FirstString -Object $payload -Paths @('agentName', 'agent_name')
  if ($delegatedFallback) { $delegatedAgentName = $delegatedFallback }
}

if ($actorName -eq 'unknown' -and $delegatedAgentName -eq 'unknown' -and $toolName -ne 'runSubagent') {
  Add-UnknownEventCounter -Path $unknownEventsPath -SessionId $sessionId -Reason 'postToolUse_unknown_context'
  exit 0
}

$eventName = if ($toolName -eq 'runSubagent') { 'delegationEnd' } else { 'postToolUse' }

$sizeBytes = [System.Text.Encoding]::UTF8.GetByteCount($inputText)
$hookExecutionMs = [int][Math]::Max(0, ((Get-Date) - $scriptStart).TotalMilliseconds)
$record = @{
  timestamp = (Get-Date).ToUniversalTime().ToString('o')
  event = $eventName
  session_id = $sessionId
  actor_name = $actorName
  actor_type = $actorType
  tool_name = $toolName
  delegated_agent_name = $delegatedAgentName
  model_used = $modelUsed
  size_bytes = $sizeBytes
  estimated_tokens = [int][math]::Ceiling($sizeBytes / 4.0)
  hook_execution_ms = $hookExecutionMs
} | ConvertTo-Json -Compress
Add-Content -Path (Join-Path $logDir 'hook-agent-call.log') -Value $record
